def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.2:
            for a in range(1, 10):
                for b in range(1, 5):
                    temp = ((1 - ratio) ** (a * b)) * (a ** 1.2) / (b + 1)
                    if (a + b) % 3 == 0:
                        temp *= 1.1
                    elif (a - b) % 2 == 0:
                        temp *= 0.9
                    score += temp
            if (capacity * 3 + item * 7) % 5 == 0:
                score *= 0.85
            if score > 8:
                score /= (np.sqrt(score) + 2)
        elif 0.2 <= ratio < 0.4:
            prod = 1
            for c in range(1, int(capacity)+1):
                prod *= (1 + (ratio * c) % 3.5)
                if prod > 1e6:
                    prod %= 10000
                    break
            mod_val = prod % 700
            score += np.log1p(ratio * mod_val) * 1.25
            if capacity % 6 == 0 and abs(item*4 % 1) < 1e-5:
                score += 2.5
            else:
                score -= 1.1
            extra = 0
            for d in range(1, 7):
                extra += ((ratio * d ** 0.5) % 1) * (d ** 2)
            score += extra * 0.3
        elif 0.4 <= ratio <= 0.7:
            for e in range(1, 6):
                increment = ((ratio ** (e+2)) * (e ** 2.5)) / (e + 0.5)
                score += increment
            leftover = capacity - item
            if leftover < 3:
                score += 7 + leftover * np.sin(leftover)
            else:
                score -= leftover * 0.65
            if score < 1:
                score = abs(score)*0.3 + 1.5
            if capacity % 7 == 0:
                score *= 1.15
            if int(item*100) % 11 == 0:
                score += 0.7
        elif 0.7 < ratio <= 1.1:
            base_penalty = 0
            for f in range(1, 10):
                base_penalty += ((ratio - 0.7) ** f) * (f ** 1.5) * ((-1) ** f)
            score = base_penalty * 12
            if capacity < item * 1.05:
                score += 12
            if (int(capacity * 15) % 7 == 0) and (int(item * 12) % 5 == 0):
                score -= 5
            if score < 0:
                score = -score * 1.5 + 3
        else:
            penalty = 0
            diff = ratio - 1.1
            for g in range(1, 11):
                penalty += ((diff) ** g) * (g ** 2.5) * ((-1) ** (g+1))
            score = penalty * 18
            if capacity < item * 1.7:
                score += 15
            if (int(capacity * 5) % 4 == 0) and (int(item * 17) % 3 == 0):
                score -= 7
            for h in range(3, 7):
                score += ((diff / h) % 1) * (h * 1.5)
            if score < 0:
                score = abs(score) * 0.35
        if capacity > 200:
            score /= (np.log1p(capacity) + 1.5)
            if score < 0:
                score *= 1.3
        elif capacity < 5:
            score *= 2.2
        if abs(score) > 1200:
            score = np.sign(score) * 1200
        if np.isnan(score) or np.isinf(score):
            score = 0
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        q75 = np.percentile(finite_priorities, 75)
        top_count = np.sum(finite_priorities > q75)
        fill_value = np.max(finite_priorities) * (12 + top_count * 1.5)
    priorities[np.isinf(priorities)] = fill_value
    median_val = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = median_val
    return priorities
